// v4.7.6: Capture everything from Airtable record in ONE place
// Added existing fields for rescore fallback
const record = $json;
return {
  json: {
    RECORD_ID: record.id,
    company_name: record['Company Name'] || '',
    company_url: record['Company URL'] || '',
    description: record['Company Description'] || '',
    source: record['VC Firm'] || record['Source'] || 'Rescore',
    existing_dq_reasons: record['Disqualify Reasons'] || '',
    existing_employee_count: record['Employee Count'] || null,
    existing_stage: record['Stage'] || null,
    existing_score: record['Tide-Pool Score'] || 0,
    searchQuery: '"' + (record['Company Name'] || '') + '" company funding employees series startup valuation'
  }
};

// v4.7.1: Rebuilder Track + Rescore Fix
// v4.7.1 fixes:
// - isRescore detection: ignore pre-existing DQ reasons when Score=0 (fresh evaluation)
// - Employee Count fallback: use Airtable field if Brave enrichment fails
// v4.7: Rebuilder Track - added rebuild signal detection for 100-300 emp companies
// v4.6: Batch 4 fixes - Employee corroboration, Funding recency, CX tooling detection

const captured = $('Capture').first().json;
const RECORD_ID = captured.RECORD_ID;
const company_name = captured.company_name;
const company_url = captured.company_url;
const description = captured.description;
const source = captured.source;
const existing_dq_reasons = captured.existing_dq_reasons || '';
const existing_employee_count = captured.existing_employee_count || null;
const existing_stage = captured.existing_stage || null;
const existing_score = captured.existing_score || 0;

// v4.7.1: Detect if this is a rescore (Score=0 but has old DQ reasons)
// If rescore, we ignore pre-existing DQ reasons and evaluate fresh
const isRescore = (existing_score === 0 || existing_score === null) && existing_dq_reasons.length > 0;

const braveResponse = $json;
const searchResults = braveResponse?.web?.results || [];
const allText = searchResults.map(r => (r.title || '') + ' ' + (r.description || '')).join(' ');

const currentYear = new Date().getFullYear();

// PE Firms (expanded list from v9.8)
const peFirms = [
  'Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'TPG', 'Carlyle',
  'Bain Capital', 'Silver Lake', 'Francisco Partners', 'Accel-KKR',
  'LLR Partners', 'Warburg Pincus', 'Apollo', 'Insight Partners', 'GTCR',
  'Clearlake', 'Welsh Carson', 'Providence Equity', 'Leonard Green',
  'Hellman & Friedman', 'Advent', 'Golden Gate Capital', 'TA Associates',
  'Brighton Park Capital', 'General Atlantic', 'Summit Partners', 'SoftBank Vision Fund',
  'EQT Partners', 'Permira', 'Jonas Software', 'Constellation Software', 'Volaris',
  'Harris Computer', 'Total Specific Solutions', 'N. Harris Computer',
  'Ares Management', 'Ares Capital', 'Spring Lake Equity', 'Vector Capital'
];

// v4.4: Known large companies (bypass enrichment errors)
const knownLargeCompanies = [
  'Zapier', 'SnapLogic', 'Stripe', 'Notion', 'Figma', 'Canva',
  'Airtable', 'Webflow', 'Monday.com', 'Asana', 'Modern Treasury',
  'Plaid', 'Brex', 'Ramp', 'Gusto', 'Rippling', 'Deel'
];

// v4.4: Known old companies (bypass enrichment errors for age gate)
const knownOldCompanies = [
  { name: 'InternMatch', founded: 2009 },
  { name: 'VoltServer', founded: 2011 },
  { name: 'Mighty Networks', founded: 2010 },
  { name: 'Helcim', founded: 2006 },
  { name: 'Zapier', founded: 2011 },
  { name: 'Mailchimp', founded: 2001 },
  { name: 'HubSpot', founded: 2006 },
  { name: 'Zendesk', founded: 2007 },
  { name: 'Intercom', founded: 2011 },
  { name: 'Drift', founded: 2015 },
  { name: 'Pendo', founded: 2013 },
  { name: 'Gainsight', founded: 2011 },
  { name: 'Mixpanel', founded: 2009 },
  { name: 'Amplitude', founded: 2012 },
  { name: 'Segment', founded: 2011 },
  { name: 'Twilio', founded: 2008 },
  { name: 'SendGrid', founded: 2009 },
  { name: 'Clearbit', founded: 2014 }
];

// v4.6: CX Tooling Keywords (companies that SELL to support teams)
const CX_TOOLING_KEYWORDS = [
  'cobrowsing', 'session replay', 'helpdesk', 'ticketing',
  'chatbot', 'customer support software', 'live chat',
  'contact center', 'support automation', 'knowledge base software',
  'customer service platform', 'help desk software', 'support ticketing'
];

// Helper: parse funding amount
const parseFundingAmount = (amountStr, unitStr) => {
  const amount = parseFloat(amountStr);
  const unit = unitStr.toLowerCase();
  if (unit === 'billion' || unit === 'b') return amount * 1000000000;
  if (unit === 'million' || unit === 'm') return amount * 1000000;
  return amount;
};

const formatFunding = (numeric) => {
  if (numeric >= 1000000000) return '$' + (numeric / 1000000000).toFixed(1) + 'B';
  if (numeric >= 1000000) return '$' + (numeric / 1000000).toFixed(1) + 'M';
  return '$' + numeric;
};

// v4.6: Helper for median calculation
const median = (arr) => {
  if (arr.length === 0) return null;
  const sorted = [...arr].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : Math.round((sorted[mid - 1] + sorted[mid]) / 2);
};

// === EXTRACT DATA ===

// v4.6: Employee count corroboration (Batch 4 Fix 4.1)
// Extract ALL employee mentions and take median for corroboration
const empMatches = [...allText.matchAll(/(\d[\d,]*)\s*(?:to\s*\d[\d,]*)?\s*employees?/gi)];
const empCounts = empMatches.map(m => parseInt(m[1].replace(/,/g, ''))).filter(n => n > 0 && n < 100000);
let employeeCount = empCounts.length > 0 ? (empCounts.length > 1 ? median(empCounts) : empCounts[0]) : null;
const employeeCountCorroborated = empCounts.length > 2;

// Range detection: "10-50 employees" -> take upper bound
const rangeMatch = allText.match(/(\d+)\s*(?:to|-)\s*(\d+)\s*employees?/i);
if (rangeMatch && !employeeCount) {
  employeeCount = parseInt(rangeMatch[2]); // Upper bound
}

// v4.7.1: Fallback to existing Airtable Employee Count if Brave extraction failed
if (!employeeCount && existing_employee_count) {
  employeeCount = existing_employee_count;
}

// v4.6: Suspicious employee count cross-reference (Batch 4 Fix 4.1)
const fundingStageRank = { 'Pre-Seed': 1, 'Seed': 2, 'Series A': 3, 'Series B': 4, 'Series C': 5, 'Series D': 6, 'Series E': 7 };
let suspiciousEmployeeCount = false;
let employeeCountFlag = null;

let fundingStage = null;
if (/Series\s*E/i.test(allText)) fundingStage = 'Series E';
else if (/Series\s*D/i.test(allText)) fundingStage = 'Series D';
else if (/Series\s*C/i.test(allText)) fundingStage = 'Series C';
else if (/Series\s*B/i.test(allText)) fundingStage = 'Series B';
else if (/Series\s*A/i.test(allText)) fundingStage = 'Series A';
else if (/\bSeed\b/i.test(allText)) fundingStage = 'Seed';

// v4.7.6: Fallback to existing Airtable Stage if Brave extraction failed
if (!fundingStage && existing_stage) {
  fundingStage = existing_stage;
}

// Total funding
let totalFunding = null, totalFundingRaw = null;
const fundingMatch = allText.match(/(?:raised|funding|total funding)\s*\$([\d.]+)\s*(million|billion|M|B)/i);
if (fundingMatch) {
  totalFunding = parseFundingAmount(fundingMatch[1], fundingMatch[2]);
  totalFundingRaw = formatFunding(totalFunding);
}

// Cross-reference: low employee count + high funding = suspicious
const isSeriesAPlus = fundingStage && fundingStageRank[fundingStage] >= 3;
const hasSignificantFunding = totalFunding && totalFunding >= 10000000;
if (employeeCount && employeeCount < 15 && (isSeriesAPlus || hasSignificantFunding)) {
  suspiciousEmployeeCount = true;
  employeeCountFlag = 'Employee count ' + employeeCount + ' seems low for ' + (fundingStage || 'significant funding') + ' with ' + (totalFundingRaw || '>$10M');
}

// v4.6: Funding recency extraction (Batch 4 Fix 4.2)
let lastFundingYear = null;
let yearsSinceLastRound = null;
let fundingRecency = null;
const fundingYearPatterns = [
  /series\s*[a-e]\s*(?:round\s*)?(?:in\s*)?(20\d{2})/i,
  /raised.*?(20\d{2})/i,
  /(20\d{2}).*?series\s*[a-e]/i,
  /(?:funding|round).*?(20\d{2})/i,
  /(?:may|june|july|aug|sep|oct|nov|dec|jan|feb|mar|apr)\s*(?:of\s*)?(20\d{2}).*?(?:series|raised|funding)/i
];
for (const pattern of fundingYearPatterns) {
  const match = allText.match(pattern);
  if (match) {
    const year = parseInt(match[1]);
    if (year >= 2015 && year <= currentYear && (!lastFundingYear || year > lastFundingYear)) {
      lastFundingYear = year;
    }
  }
}
if (lastFundingYear) {
  yearsSinceLastRound = currentYear - lastFundingYear;
  if (yearsSinceLastRound < 1) fundingRecency = 'recent';
  else if (yearsSinceLastRound < 2) fundingRecency = 'moderate';
  else if (yearsSinceLastRound < 3) fundingRecency = 'aging';
  else fundingRecency = 'stale';
}

// v4.6: Graduated funding staleness modifier (Batch 4 Fix 4.2)
const isEarlyStage = ['Seed', 'Series A'].includes(fundingStage);
let fundingStalenessModifier = 0;
if (yearsSinceLastRound && isEarlyStage && (!employeeCount || employeeCount < 100)) {
  if (yearsSinceLastRound >= 4) fundingStalenessModifier = -15;
  else if (yearsSinceLastRound >= 3) fundingStalenessModifier = -10;
  else if (yearsSinceLastRound >= 2) fundingStalenessModifier = -5;
}

// v4.6: CX Tooling Company Detection (Batch 4 Fix 4.4)
let isCXToolingCompany = false;
let cxToolingSignals = [];
const allTextLower = allText.toLowerCase();
for (const keyword of CX_TOOLING_KEYWORDS) {
  if (allTextLower.includes(keyword.toLowerCase())) {
    cxToolingSignals.push(keyword);
  }
}
isCXToolingCompany = cxToolingSignals.length >= 2;

// v4.7: REBUILD SIGNAL DETECTION (for companies with 100-300 employees)
let rebuildSignal = false;
let rebuildLeader = null;
let rebuildLeaderStart = null;
const isInRebuildRange = employeeCount && employeeCount >= 100 && employeeCount <= 300;
if (isInRebuildRange) {
  // Look for CS/CX leadership hired in last 12 months
  const rebuildPatterns = [
    /(?:hired|appointed|welcomed|joined|named)\s+(?:as\s+)?(?:our\s+)?(?:new\s+)?(?:CCO|Chief Customer Officer|VP (?:of )?Customer (?:Success|Experience)|Head of Customer (?:Success|Experience)|VP CS|VP CX|Chief Customer|Chief Experience Officer)/gi,
    /(?:CCO|Chief Customer Officer|VP (?:of )?Customer (?:Success|Experience)|Head of Customer (?:Success|Experience))\s+(?:hired|appointed|joined|started|welcomes|announced)/gi,
    /new (?:CCO|Chief Customer Officer|VP (?:of )?Customer|Head of Customer)/gi,
    /(?:joins|joined)\s+(?:as|the company as)\s+(?:CCO|Chief Customer Officer|VP (?:of )?Customer|Head of Customer)/gi
  ];
  for (const pattern of rebuildPatterns) {
    const match = allText.match(pattern);
    if (match) {
      rebuildSignal = true;
      rebuildLeader = match[0].substring(0, 100);
      // Try to extract date if present
      const dateMatch = allText.match(new RegExp(match[0].replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '[^.]*?(202[456]|January|February|March|April|May|June|July|August|September|October|November|December)', 'i'));
      if (dateMatch) rebuildLeaderStart = dateMatch[1];
      break;
    }
  }
}

// v4.4: Valuation extraction (for unicorn gate)
let valuation = null, valuationRaw = null;
if (/\bunicorn\b/i.test(allText)) {
  valuation = 1000000000;
  valuationRaw = '$1.0B (unicorn)';
} else {
  const valuationMatch = allText.match(/(?:valued at|valuation of?)\s*\$([\d.]+)\s*(million|billion|M|B)/i);
  if (valuationMatch) {
    valuation = parseFundingAmount(valuationMatch[1], valuationMatch[2]);
    valuationRaw = formatFunding(valuation);
  }
}

// Founded year - first check known old companies list, then try enrichment
let foundedYear = null;
const knownOldMatch = knownOldCompanies.find(c => company_name && company_name.toLowerCase().includes(c.name.toLowerCase()));
if (knownOldMatch) {
  foundedYear = knownOldMatch.founded;
} else {
  const foundMatch = allText.match(/(?:founded|established|since)\s*(?:in)?\s*(\d{4})/i);
  if (foundMatch) foundedYear = parseInt(foundMatch[1]);
}

// v4.4: Company age calculation
const companyAge = foundedYear ? (currentYear - foundedYear) : null;
const isTooOld = companyAge !== null && companyAge > 8;
const isAgingFlag = companyAge !== null && companyAge > 5 && companyAge <= 8;
const isKnownOldCompany = knownOldMatch !== undefined;

// PE detection
const isPEBacked = peFirms.some(f => new RegExp(f, 'i').test(allText));
const peBackerFound = peFirms.find(f => new RegExp(f, 'i').test(allText)) || null;

// v4.4: Known large company check
const isKnownLargeCompany = knownLargeCompanies.some(name => 
  company_name && company_name.toLowerCase().includes(name.toLowerCase())
);

// Status flags
const isAcquired = /\b(acquired|was acquired|acquisition|merged with|bought by|shut down|defunct)\b/i.test(allText);
const isPublic = /\b(NYSE|NASDAQ|publicly traded|IPO|went public|stock ticker)\b/i.test(allText);

// === SECTOR DETECTION (v9.7 aligned) ===
const isBiotech = /\b(therapeutic|drug development|clinical trial|pharma|biotech|oncology|immunotherapy)\b/i.test(allText);
const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|semiconductor|solar|battery|EV charging)\b/i.test(allText) && !/\bSaaS\b/i.test(allText);
const isCrypto = /\b(blockchain|cryptocurrency|web3|NFT|DeFi|token|crypto|decentralized)\b/i.test(allText);
const isConsumer = /\b(consumer app|DTC|direct-to-consumer|B2C|telehealth|patient app|consumer health)\b/i.test(allText);
const isHRTech = /\b(HR tech|human resources|DEI|diversity equity|workforce analytics|recruiting platform|HRIS|payroll)\b/i.test(allText);
const isMarketplace = /\b(marketplace|two-sided market|gig economy|freelance platform|labor marketplace)\b/i.test(allText) && !/\b(SaaS|software platform|enterprise)\b/i.test(allText);

// v4.4: New sector gates from v9.7
const isFintech = /\b(fintech|banking software|credit union|neobank|payment processing|lending platform|loan origination|mortgage tech|banking as a service|BaaS|open banking|core banking)\b/i.test(allText) && !/\b(healthcare billing|medical billing|revenue cycle)\b/i.test(allText);
const isConstructionTech = /\b(construction (?:tech|software|management)|general contractor|subcontractor management|job site|building information|BIM software)\b/i.test(allText);
const isFoodBiotech = /\b(fermentation|food science|food tech|cultured (?:meat|protein)|alternative protein|CPG brand|consumer packaged goods|beverage brand)\b/i.test(allText);
const isPhysicalSecurity = /\b(physical security|access control|surveillance|security camera|weapon detection|metal detector|perimeter security)\b/i.test(allText) && !/\b(cybersecurity|data security|cloud security)\b/i.test(allText);
const isInsurtech = /\b(insurtech|insurance (?:technology|software|platform)|policy management|claims processing|underwriting)\b/i.test(allText) && !/\b(healthcare|health plan|benefits administration)\b/i.test(allText);
const isSaaSManagement = /\b(SaaS management|software spend|IT asset management|license management|shadow IT|SaaS operations)\b/i.test(allText);
const isConsumerDigitalHealth = /\b(mental health app|therapy app|meditation app|wellness app|patient (?:portal|app)|health coaching app|digital therapeutic|DTx|fertility app|pregnancy app)\b/i.test(allText) && !/\b(provider-facing|clinician-facing|EHR|clinical workflow)\b/i.test(allText);

// v4.4: GTM Motion detection (PLG-dominant gate)
const plgSignals = [
  /free (?:tier|plan|trial)/i,
  /self[\s-]?serve/i,
  /product[\s-]?led/i,
  /freemium/i,
  /open[\s-]?source/i,
  /sign up free/i
];
const enterpriseSignals = [
  /enterprise (?:sales|team|customers)/i,
  /account (?:executive|manager)/i,
  /sales[\s-]?led/i,
  /high[\s-]?touch/i,
  /customer success (?:team|manager)/i,
  /enterprise[\s-]?grade/i
];
const plgSignalCount = plgSignals.filter(p => p.test(allText)).length;
const enterpriseSignalCount = enterpriseSignals.filter(p => p.test(allText)).length;
const isPLGDominant = plgSignalCount >= 3 && enterpriseSignalCount < 2;

// === BUILD DISQUALIFIERS ===
const disqualifiers = [];
const flagsForReview = []; // v4.6: Soft flags for manual review

// v4.7.1: Handle pre-existing DQ reasons - skip if this is a rescore
if (!isRescore && existing_dq_reasons.length > 0) {
  if (!existing_dq_reasons.startsWith('Pre-existing DQ:')) {
    disqualifiers.push('Pre-existing DQ: ' + existing_dq_reasons);
  } else {
    disqualifiers.push(existing_dq_reasons);
  }
}
// If isRescore=true, we intentionally ignore old DQ reasons and evaluate fresh

// TIER 1: HARD GATES
if (isAcquired) disqualifiers.push('Acquired');
if (isPEBacked) disqualifiers.push('PE-backed (' + peBackerFound + ')');
if (isKnownLargeCompany) disqualifiers.push('Known large company (enrichment bypass)');

// v4.6: Modified employee count gate - route suspicious counts to review instead of auto-DQ
if (employeeCount && employeeCount > 350) {
  disqualifiers.push('Too large (>' + 350 + ' employees: ' + employeeCount + ')');
} else if (suspiciousEmployeeCount) {
  // Route to manual review instead of auto-DQ
  flagsForReview.push(employeeCountFlag);
}

if (totalFunding && totalFunding > 450000000) disqualifiers.push('>$450M funding (' + totalFundingRaw + ')');

// v4.4: Unicorn gate (mutually exclusive with >$450M valuation)
if (valuation && valuation >= 1000000000) {
  disqualifiers.push('Unicorn valuation (>$1B: ' + valuationRaw + ')');
} else if (valuation && valuation > 500000000) {
  disqualifiers.push('>$500M valuation (' + valuationRaw + ')');
}

if (isPublic) disqualifiers.push('Public company');
if (['Series D', 'Series E'].includes(fundingStage)) disqualifiers.push('Late stage (' + fundingStage + ')');

// v4.4: Company age gate
if (isTooOld) disqualifiers.push('Company too old (' + companyAge + ' years)');

// TIER 2: SECTOR GATES
if (isBiotech) disqualifiers.push('Biotech/pharma');
if (isHardware) disqualifiers.push('Hardware');
if (isCrypto) disqualifiers.push('Crypto/Web3');
if (isConsumer) disqualifiers.push('Consumer/B2C');
if (isHRTech) disqualifiers.push('HR Tech');
if (isMarketplace) disqualifiers.push('Marketplace');
// v4.4: New sector gates
if (isFintech) disqualifiers.push('Fintech/Banking (wrong sector)');
if (isConstructionTech) disqualifiers.push('Construction Tech (wrong sector)');
if (isFoodBiotech) disqualifiers.push('Food science/CPG (not B2B SaaS)');
if (isPhysicalSecurity) disqualifiers.push('Physical security hardware (wrong sector)');
if (isInsurtech) disqualifiers.push('Insurtech (wrong sector)');
if (isSaaSManagement) disqualifiers.push('SaaS management (wrong buyer persona)');
if (isConsumerDigitalHealth) disqualifiers.push('Consumer digital health (patient-facing)');

// TIER 3: GTM MOTION GATES
if (isPLGDominant) disqualifiers.push('PLG-dominant (no enterprise CS need)');

// TIER 5: SOFT GATES - <15 employees moved to warnings section (not a hard DQ)
// Early-stage companies are builder opportunities to monitor

// v4.7: Headcount penalty modifier (per spec Phase 2)
let headcountPenaltyModifier = 0;
if (employeeCount && employeeCount >= 200 && employeeCount <= 350) {
  if (rebuildSignal) {
    headcountPenaltyModifier = 0; // No penalty if rebuild signal detected
  } else {
    headcountPenaltyModifier = -10; // -10 penalty without rebuild signal
  }
} else if (employeeCount && employeeCount >= 150 && employeeCount < 200) {
  if (rebuildSignal) {
    headcountPenaltyModifier = 0; // No penalty if rebuild signal
  } else {
    headcountPenaltyModifier = -5; // -5 penalty without rebuild signal
  }
}

// Warnings (for logging, not DQ)
const warnings = [];
if (employeeCount && employeeCount < 15 && !suspiciousEmployeeCount) warnings.push('Early stage (<15 employees) - monitor for growth');
if (isAgingFlag) warnings.push('Company aging (' + companyAge + ' years old)');
if (employeeCount && employeeCount >= 200 && employeeCount <= 350) {
  if (rebuildSignal) {
    warnings.push('Employee count ' + employeeCount + ' in rebuild range - no penalty (rebuild signal detected)');
  } else {
    warnings.push('Employee count ' + employeeCount + ' in penalty zone (-10 modifier)');
  }
}
if (fundingRecency === 'stale') warnings.push('Stale funding (' + yearsSinceLastRound + ' years since last round)');
if (isCXToolingCompany) warnings.push('CX tooling company (sells TO support teams): ' + cxToolingSignals.join(', '));

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: company_name,
    company_url: company_url,
    description: description,
    source: source,
    funding_stage: fundingStage,
    total_funding: totalFundingRaw,
    total_funding_numeric: totalFunding,
    valuation: valuationRaw,
    valuation_numeric: valuation,
    employee_count: employeeCount,
    employee_count_corroborated: employeeCountCorroborated,
    suspicious_employee_count: suspiciousEmployeeCount,
    employee_count_flag: employeeCountFlag,
    pe_backed: isPEBacked,
    founded_year: foundedYear,
    company_age: companyAge,
    is_too_old: isTooOld,
    is_aging_flag: isAgingFlag,
    is_known_large_company: isKnownLargeCompany,
    is_plg_dominant: isPLGDominant,
    // v4.6: Funding recency fields
    last_funding_year: lastFundingYear,
    years_since_last_round: yearsSinceLastRound,
    funding_recency: fundingRecency,
    funding_staleness_modifier: fundingStalenessModifier,
    // v4.6: CX tooling fields
    is_cx_tooling_company: isCXToolingCompany,
    cx_tooling_signals: cxToolingSignals.join(', '),
    // v4.7: Rebuild signal fields
    rebuild_signal: rebuildSignal,
    rebuild_leader: rebuildLeader,
    rebuild_leader_start: rebuildLeaderStart,
    headcount_penalty_modifier: headcountPenaltyModifier,
    // v4.6: Flags for review
    flags_for_review: flagsForReview.join('; '),
    disqualify_reasons: disqualifiers.join('; '),
    isAutoDisqualified: disqualifiers.length > 0,
    warnings: warnings
  }
};

// v4.6: Added Batch 4 field pass-through
const prev = $('Build Persona').first().json;
const RECORD_ID = prev.RECORD_ID;

const response = $json;
let persona = 'unknown';
try {
  const content = response.content?.[0]?.text || '';
  const clean = content.toLowerCase().trim();
  if (clean.includes('business')) persona = 'business-user';
  else if (clean.includes('developer')) persona = 'developer';
  else if (clean.includes('mixed')) persona = 'mixed';
} catch (e) {
  console.error('Persona parse error:', e.message);
}

// Only auto-pass developers if employee_count is known and < 50 (Opus review fix)
const shouldAutoPass = persona === 'developer' && prev.employee_count !== null && prev.employee_count < 50;

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: prev.company_name,
    company_url: prev.company_url,
    description: prev.description,
    source: prev.source,
    funding_stage: prev.funding_stage,
    total_funding: prev.total_funding,
    employee_count: prev.employee_count,
    pe_backed: prev.pe_backed,
    founded_year: prev.founded_year,
    company_age: prev.company_age,
    is_aging_flag: prev.is_aging_flag,
    // v4.5: Carry through job/network fields
    hasActiveJobPosting: prev.hasActiveJobPosting,
    hasCXJobPosting: prev.hasCXJobPosting,
    matchingJobTitles: prev.matchingJobTitles,
    hasNetworkConnection: prev.hasNetworkConnection,
    connectionName: prev.connectionName,
    connectionLinkedInURL: prev.connectionLinkedInURL,
    // v4.6: Batch 4 fields
    funding_recency: prev.funding_recency,
    years_since_last_round: prev.years_since_last_round,
    funding_staleness_modifier: prev.funding_staleness_modifier,
    is_cx_tooling_company: prev.is_cx_tooling_company,
    cx_tooling_signals: prev.cx_tooling_signals,
    suspicious_employee_count: prev.suspicious_employee_count,
    employee_count_flag: prev.employee_count_flag,
    // v4.7: Rebuild signal fields
    rebuild_signal: prev.rebuild_signal,
    rebuild_leader: prev.rebuild_leader,
    rebuild_leader_start: prev.rebuild_leader_start,
    headcount_penalty_modifier: prev.headcount_penalty_modifier,
    customer_persona: persona,
    developer_auto_pass: shouldAutoPass
  }
};

// v4.7: Rebuilder Track - added REBUILDER role_type classification
// v4.6: Updated eval prompt with CX tooling distinction, funding recency, suspicious employee count
const c = $json;
const agingNote = c.is_aging_flag ? ' Company is ' + c.company_age + ' years old (aging flag).' : '';

// v4.6: Build context notes for new Batch 4 signals
let contextNotes = [];
if (c.is_cx_tooling_company) {
  contextNotes.push('CX TOOLING VENDOR FLAG: This company sells customer support software (signals: ' + c.cx_tooling_signals + '). Companies that SELL CX tools do NOT need CS leadership - they sell TO support teams, not BUILD large CS orgs. Set sector_match to unrelated and cs_hire_likelihood to unlikely.');
}
if (c.funding_recency === 'stale' && c.funding_staleness_modifier < 0) {
  contextNotes.push('STALE FUNDING FLAG: Last funding was ' + c.years_since_last_round + ' years ago (' + (c.funding_stage || 'early stage') + '). Apply ' + c.funding_staleness_modifier + ' point penalty. Likely zombie company without growth.');
}
if (c.suspicious_employee_count) {
  contextNotes.push('SUSPICIOUS EMPLOYEE COUNT: ' + c.employee_count_flag + '. Manual review needed - enrichment may have picked up stray integer instead of real headcount.');
}
// v4.7: Rebuild signal detection
if (c.rebuild_signal) {
  contextNotes.push('REBUILD SIGNAL: New CS leadership detected (' + (c.rebuild_leader || 'CCO/VP CS') + '). Apply +20 rebuild bonus. Company has 100-300 employees and new CS executive is building their team. Classify as REBUILDER not MAINTAINER.');
}
const contextSection = contextNotes.length > 0 ? ' CONTEXT FLAGS: ' + contextNotes.join(' | ') : '';

const evalPrompt = 'COMPANY: ' + c.company_name + '. URL: ' + c.company_url + '. Description: ' + c.description + '. Funding: ' + (c.funding_stage || 'Unknown') + '. Employees: ' + (c.employee_count || 'Unknown') + '. Founded: ' + (c.founded_year || 'Unknown') + '. Persona: ' + c.customer_persona + '.' + agingNote + contextSection + ' Score 0-100 for job search fit (VP/Head of Customer Support/Success). CS HIRE READINESS (Leadership Gap): HIGH (20-25): No CS team exists OR frontline CSMs exist but no Director+ leader OR CS leadership recently turned over (<12 months). MEDIUM (10-19): Small CS team (2-5) with team lead but no senior leader. LOW (0-9): Stable CS leadership >12 months with fully staffed team. CRITICAL: CSMs existing is NOT negative - a company with 5 CSMs and no CS Director has HIGHER readiness than 0 CSMs where founder answers tickets. The question is whether there is a LEADERSHIP GAP. RULES: (1) cs_readiness_score requires EVIDENCE. If no evidence of CS team building, score 0 and state "No evidence of CS leadership gap found." Do NOT infer CS need from funding stage alone. (2) CX TOOLING COMPANIES that sell support software should have cs_hire_likelihood=unlikely and sector_match=unrelated. (3) STALE FUNDING at early stage = apply penalty in scoring. Return JSON: {"bucket":"APPLY|WATCH|PASS","total_score":N,"sector_match":"target|adjacent|unrelated","cs_hire_likelihood":"high|medium|low|unlikely","product_type":"enterprise|mid-market|self-serve","domain_distance":"target|adjacent|high-distance","domain_distance_modifier":N,"gtm_motion":"enterprise|plg|hybrid","role_type":"builder|rebuilder|maintainer|mixed","cs_readiness_score":N,"cs_readiness_reasoning":"evidence-based explanation","summary":"2 sentences"}. For domain_distance_modifier: target domains like healthcare B2B SaaS get +3 to +5, adjacent domains get 0, high-distance domains like ITSM/Legal/RealEstate get -5 to -10.';

return {
  json: {
    RECORD_ID: c.RECORD_ID,
    company_name: c.company_name,
    funding_stage: c.funding_stage,
    total_funding: c.total_funding,
    employee_count: c.employee_count,
    pe_backed: c.pe_backed,
    founded_year: c.founded_year,
    customer_persona: c.customer_persona,
    // v4.5: Carry through job/network fields
    hasActiveJobPosting: c.hasActiveJobPosting,
    hasCXJobPosting: c.hasCXJobPosting,
    matchingJobTitles: c.matchingJobTitles,
    hasNetworkConnection: c.hasNetworkConnection,
    connectionName: c.connectionName,
    connectionLinkedInURL: c.connectionLinkedInURL,
    // v4.7: Rebuild signal fields
    rebuild_signal: c.rebuild_signal || false,
    rebuild_leader: c.rebuild_leader || null,
    headcount_penalty_modifier: c.headcount_penalty_modifier || 0,
    evalPrompt: evalPrompt
  }
};

// v4.6: Batch 4 - Added CS Hire Readiness score capping and scoring breakdown
const prev = $('Build Eval').first().json;
const RECORD_ID = prev.RECORD_ID;

const response = $json;
let evaluation = { bucket: 'WATCH', total_score: 0, summary: 'Parse error' };
try {
  const content = response.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
} catch (e) {
  console.error('Eval parse error:', e.message);
}

// v4.7: Apply rebuild bonus BEFORE capping
let finalScore = evaluation.total_score || 0;
let originalScore = finalScore;
let rebuildBonusApplied = false;
if (prev.rebuild_signal) {
  finalScore += 20;
  rebuildBonusApplied = true;
}

// v4.6: CS Hire Readiness Score Capping (Batch 4 Fix 4.3)
let scoreCapped = false;
let scoreCapReason = null;

const csHireLikelihood = (evaluation.cs_hire_likelihood || '').toLowerCase();

// Graduated caps: unlikely=65, low=75 (Opus review improvement)
if (csHireLikelihood === 'unlikely') {
  if (finalScore > 65) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 65: CS hire likelihood is unlikely';
    finalScore = 65;
  }
} else if (csHireLikelihood === 'low') {
  if (finalScore > 75) {
    scoreCapped = true;
    scoreCapReason = 'Score capped from ' + finalScore + ' to 75: CS hire likelihood is low';
    finalScore = 75;
  }
}

// v4.7: Apply headcount penalty modifier
if (prev.headcount_penalty_modifier && prev.headcount_penalty_modifier < 0) {
  const beforeHeadcount = finalScore;
  finalScore = Math.max(0, finalScore + prev.headcount_penalty_modifier);
  if (!scoreCapped) {
    scoreCapReason = 'Headcount penalty: ' + prev.headcount_penalty_modifier + ' (from ' + beforeHeadcount + ' to ' + finalScore + ')';
  } else {
    scoreCapReason = scoreCapReason + ' | Headcount penalty: ' + prev.headcount_penalty_modifier;
  }
}

// v4.6: Apply funding staleness modifier
if (prev.funding_staleness_modifier && prev.funding_staleness_modifier < 0) {
  const beforeMod = finalScore;
  finalScore = Math.max(0, finalScore + prev.funding_staleness_modifier);
  if (!scoreCapped) {
    scoreCapReason = 'Funding staleness modifier: ' + prev.funding_staleness_modifier + ' (from ' + beforeMod + ' to ' + finalScore + ')';
  } else {
    scoreCapReason = scoreCapReason + ' | Funding staleness modifier: ' + prev.funding_staleness_modifier;
  }
}

// v4.6: Recalculate bucket based on capped score
let bucket = evaluation.bucket;
if (scoreCapped || prev.funding_staleness_modifier < 0) {
  if (finalScore >= 70) bucket = 'APPLY';
  else if (finalScore >= 40) bucket = 'WATCH';
  else bucket = 'PASS';
}

// v4.2: Updated status mapping (removed Skip, use Passed)
const statusMap = { 'APPLY': 'Apply', 'WATCH': 'Monitor', 'PASS': 'Passed' };

// Valid Airtable select options
const validDomainDistance = ['target', 'adjacent', 'high-distance'];
const validGtmMotion = ['enterprise', 'plg', 'hybrid'];
const validRoleType = ['builder', 'rebuilder', 'maintainer', 'mixed'];
const validSectorMatch = ['target', 'adjacent', 'unrelated'];
const validCsHire = ['high', 'medium', 'low', 'unlikely'];
const validProductType = ['enterprise', 'mid-market', 'self-serve'];
const validPersona = ['business-user', 'developer', 'employee-user', 'mixed'];

// v4.6: Build scoring breakdown for debugging
const scoringBreakdown = {
  original_score: originalScore,
  final_score: finalScore,
  score_capped: scoreCapped,
  cap_reason: scoreCapReason,
  cs_hire_likelihood: csHireLikelihood,
  funding_staleness_modifier: prev.funding_staleness_modifier || 0,
  domain_distance_modifier: evaluation.domain_distance_modifier || 0,
  cs_readiness_score: evaluation.cs_readiness_score || 0,
  is_cx_tooling_company: prev.is_cx_tooling_company || false,
  suspicious_employee_count: prev.suspicious_employee_count || false,
  rebuild_signal: prev.rebuild_signal || false,
  rebuild_bonus_applied: rebuildBonusApplied,
  headcount_penalty_modifier: prev.headcount_penalty_modifier || 0
};

// Build fields object conditionally (omit select fields if invalid)
const fields = {
  'Status': statusMap[bucket] || 'Research',
  'Tide-Pool Score': finalScore,
  'Summary': (scoreCapped ? '[CAPPED] ' : '') + (evaluation.summary || ''),
  'Stage': prev.funding_stage || '',
  'Total Funding': prev.total_funding || '',
  'Employee Count': prev.employee_count || null,
  'PE Backed': prev.pe_backed || false,
  'Founded Year': prev.founded_year || null,
  'Domain Distance Modifier': evaluation.domain_distance_modifier || 0,
  'CS Readiness Score': evaluation.cs_readiness_score || null,
  // v4.5: Add job/network fields
  'Has Active Job Posting': prev.hasActiveJobPosting || false,
  'Has CX Job Posting': prev.hasCXJobPosting || false,
  'Matching Job Titles': prev.matchingJobTitles || '',
  'Has Network Connection': prev.hasNetworkConnection || false,
  'Connection Name': prev.connectionName || '',
  'Connection LinkedIn URL': prev.connectionLinkedInURL || ''
  // Note: v4.6/v4.7 fields (Rebuild Signal, Scoring Breakdown, etc.) omitted - not in Airtable schema
};

// Only add select fields if they have valid values
if (validSectorMatch.includes(evaluation.sector_match)) fields['Sector Match'] = evaluation.sector_match;
if (validCsHire.includes(csHireLikelihood)) fields['CS Hire Likelihood'] = csHireLikelihood;
if (validProductType.includes(evaluation.product_type)) fields['Product Type'] = evaluation.product_type;
if (validPersona.includes(prev.customer_persona)) fields['Customer Persona'] = prev.customer_persona;
if (validDomainDistance.includes(evaluation.domain_distance)) fields['Domain Distance'] = evaluation.domain_distance;
if (validGtmMotion.includes(evaluation.gtm_motion)) fields['GTM Motion'] = evaluation.gtm_motion;
if (validRoleType.includes(evaluation.role_type)) fields['Role Type'] = evaluation.role_type;

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: prev.company_name,
    airtableFields: fields
  }
};

// v4.5: Job & Network Cross-Reference
// Get company data from upstream
const companyData = $('Parse Enrich').first().json;
const companyName = (companyData.company_name || '').toLowerCase().trim();

// Guard against empty/short company names (Opus review fix)
const companyNameClean = companyName
  .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

if (!companyNameClean || companyNameClean.length < 2) {
  // Return empty matches for invalid company names
  return {
    json: {
      ...companyData,
      hasActiveJobPosting: false,
      hasCXJobPosting: false,
      matchingJobTitles: '',
      hasNetworkConnection: false,
      connectionName: '',
      connectionLinkedInURL: '',
      _jobMatchCount: 0,
      _connectionMatchCount: 0,
    }
  };
}

// For short names (< 4 chars), use exact match only to avoid false positives
const useExactOnly = companyNameClean.length < 4;

// --- JOB LISTINGS MATCHING ---
let jobResults = [];
try {
  jobResults = $('Search Job Listings').all() || [];
} catch(e) {
  console.error('Search Job Listings error:', e.message);
  jobResults = [];
}

const matchedJobs = jobResults.filter(job => {
  const jobCompany = (job.json.Company || '').toLowerCase()
    .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  if (!jobCompany) return false;
  if (useExactOnly) return jobCompany === companyNameClean;
  return jobCompany === companyNameClean ||
         jobCompany.includes(companyNameClean) ||
         companyNameClean.includes(jobCompany);
});

const hasActiveJob = matchedJobs.length > 0;
const jobTitles = matchedJobs.map(j => j.json['Job Title']).filter(Boolean);

// CX/CS/Support job detection
const CX_PATTERNS = [
  /customer success/i,
  /customer support/i,
  /customer experience/i,
  /client success/i,
  /client services/i,
  /\bcs\b.*(?:manager|lead|director|vp|head)/i,
  /\bcx\b.*(?:manager|lead|director|vp|head)/i,
  /support.*(?:manager|lead|director|vp|head)/i,
  /(?:head|vp|director).*(?:support|success|experience)/i,
  /implementation/i,
  /onboarding.*(?:manager|lead|director)/i,
];

const hasCXJob = matchedJobs.some(job => {
  const title = job.json['Job Title'] || '';
  return CX_PATTERNS.some(p => p.test(title));
});

// --- LINKEDIN CONNECTIONS MATCHING ---
let connectionResults = [];
try {
  connectionResults = $('Search LinkedIn Connections').all() || [];
} catch(e) {
  console.error('Search LinkedIn Connections error:', e.message);
  connectionResults = [];
}

const matchedConnections = connectionResults.filter(conn => {
  const connCompany = (conn.json['Company Normalized'] || conn.json['Company'] || '')
    .toLowerCase()
    .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  if (!connCompany) return false;
  if (useExactOnly) return connCompany === companyNameClean;
  return connCompany === companyNameClean ||
         connCompany.includes(companyNameClean) ||
         companyNameClean.includes(connCompany);
});

const hasNetworkConnection = matchedConnections.length > 0;

// Pick the most relevant connection (prefer senior roles)
let connectionName = '';
let connectionURL = '';
if (hasNetworkConnection) {
  const SENIORITY_KEYWORDS = /vp|vice president|director|head|chief|founder|ceo|coo|cro|cto/i;
  const sorted = matchedConnections.sort((a, b) => {
    const aScore = SENIORITY_KEYWORDS.test(a.json.Position || '') ? 1 : 0;
    const bScore = SENIORITY_KEYWORDS.test(b.json.Position || '') ? 1 : 0;
    return bScore - aScore;
  });
  connectionName = sorted[0].json.Name || '';
  connectionURL = sorted[0].json['LinkedIn URL'] || '';
}

// --- OUTPUT ---
// Merge with existing company data and pass through
return {
  json: {
    ...companyData,
    hasActiveJobPosting: hasActiveJob,
    hasCXJobPosting: hasCXJob,
    matchingJobTitles: jobTitles.join(', '),
    hasNetworkConnection: hasNetworkConnection,
    connectionName: connectionName,
    connectionLinkedInURL: connectionURL,
    _jobMatchCount: matchedJobs.length,
    _connectionMatchCount: matchedConnections.length,
  }
};
